"""Generate a self-contained interactive responsible-AI dashboard."""

from __future__ import annotations

import json
import sqlite3
from pathlib import Path


def create_report(db_path: Path, evaluation: dict, output: Path) -> None:
    with sqlite3.connect(db_path) as conn:
        conn.row_factory = sqlite3.Row
        data = {
            "evaluation": evaluation,
            "languages": [dict(r) for r in conn.execute("SELECT * FROM language_metrics")],
            "subgroups": [dict(r) for r in conn.execute("SELECT * FROM subgroup_metrics")],
            "queues": [dict(r) for r in conn.execute("SELECT * FROM queue_metrics")],
            "confusion": [dict(r) for r in conn.execute("SELECT * FROM confusion_matrix")],
            "reviews": [dict(r) for r in conn.execute("SELECT * FROM review_queue")],
            "daily": [dict(r) for r in conn.execute("SELECT * FROM daily_monitoring")],
        }
    payload = json.dumps(data).replace("</", "<\\/")
    output.parent.mkdir(parents=True, exist_ok=True)
    output.write_text(TEMPLATE.replace("__DATA__", payload), encoding="utf-8")


TEMPLATE = r'''<!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><meta name="description" content="Responsible AI support-ticket intelligence dashboard"><title>Responsible AI · Support Intelligence</title><style>
:root{--navy:#102b45;--blue:#1769aa;--cyan:#2d93c9;--green:#20a761;--orange:#f19a13;--red:#c83c32;--ink:#16324a;--muted:#6a7b8e;--line:#dce5ed;--paper:#f3f7fa}*{box-sizing:border-box}body{margin:0;background:#e8eff5;color:var(--ink);font:15px Inter,system-ui,-apple-system,Segoe UI,sans-serif}.shell{max-width:1440px;margin:auto;background:#fff;min-height:100vh;box-shadow:0 18px 70px #102b4525}.hero{padding:34px 42px;background:linear-gradient(125deg,#0b2943,#104f78);color:#fff;display:flex;justify-content:space-between;align-items:end;gap:25px}.hero h1{font-size:clamp(30px,4vw,51px);line-height:1;margin:8px 0}.hero p{color:#bad4e5;font-size:17px;margin:0}.eyebrow{color:#80d6ff;font-weight:800;letter-spacing:2px;font-size:12px}.status{padding:16px 20px;border:1px solid #ffffff35;background:#ffffff12;border-radius:12px;min-width:220px}.status b{display:block;color:#82efae;font-size:19px;margin-top:4px}.toolbar{display:flex;gap:9px;align-items:center;padding:15px 32px;position:sticky;top:0;background:#fff;z-index:4;border-bottom:1px solid var(--line);box-shadow:0 4px 14px #1232}.toolbar span{font-weight:800;margin-right:7px}.filter{padding:8px 14px;border-radius:999px;border:1px solid #c8d4df;background:#fff;font-weight:750;color:var(--ink);cursor:pointer}.filter.active{background:var(--blue);color:#fff;border-color:var(--blue)}main{padding:25px 32px 45px}.kpis{display:grid;grid-template-columns:repeat(5,1fr);gap:13px}.kpi{padding:16px;border:1px solid var(--line);border-top:5px solid var(--blue);border-radius:9px}.kpi:nth-child(2){border-top-color:var(--green)}.kpi:nth-child(3){border-top-color:var(--orange)}.kpi:nth-child(4){border-top-color:var(--cyan)}.kpi:nth-child(5){border-top-color:var(--red)}.kpi label{font-size:11px;letter-spacing:.6px;text-transform:uppercase;font-weight:850;color:var(--muted)}.kpi strong{font-size:29px;display:block;margin:5px 0}.kpi small{color:var(--muted)}.grid{display:grid;grid-template-columns:1fr 1.35fr 1fr;gap:15px;margin-top:15px}.panel{border:1px solid var(--line);border-radius:9px;overflow:hidden;background:white}.panel h2{margin:0;padding:12px 15px;background:var(--blue);color:#fff;font-size:16px}.panel.green h2{background:var(--green)}.panel.orange h2{background:var(--orange)}.panel.red h2{background:var(--red)}.body{padding:16px}.span2{grid-column:span 2}.decision{background:#e7f8ee;border-left:5px solid var(--green);padding:14px;margin-bottom:13px;border-radius:5px}.decision b{display:block;color:#148448;font-size:19px}.check{display:flex;justify-content:space-between;padding:9px 0;border-bottom:1px solid var(--line)}.pass{color:#148448}.warn{color:#b66b00}.chart-title{color:var(--muted);font-size:12px;text-transform:uppercase;letter-spacing:.6px;font-weight:850;margin:2px 0 12px}.bar-row{display:grid;grid-template-columns:115px 1fr 62px;gap:8px;align-items:center;margin:10px 0}.track{height:13px;border-radius:7px;background:#e8eef3;overflow:hidden}.bar{height:100%;border-radius:7px;transition:width .45s}.bars{min-height:218px}.legend{display:flex;gap:14px;justify-content:center;color:var(--muted);font-size:12px}.line-wrap{height:245px}.line-wrap svg{height:100%;width:100%;overflow:visible}.gridline{stroke:#e5ebf1}.axis{stroke:#becbd6}.accuracy{fill:none;stroke:var(--green);stroke-width:3}.automation{fill:none;stroke:var(--blue);stroke-width:3}.matrix{display:grid;grid-template-columns:120px repeat(5,1fr);font-size:11px;gap:3px}.cell{padding:8px 4px;text-align:center;border-radius:3px;background:#eef3f7}.cell.head{font-weight:800;background:#dfe8ef}.review{padding:10px 0;border-bottom:1px solid var(--line)}.review b{display:flex;justify-content:space-between}.tag{display:inline-block;padding:3px 7px;background:#fff1d8;color:#a45d00;border-radius:12px;font-size:11px}.insight{background:#fff7e7;border-left:4px solid var(--orange);padding:11px;margin:12px 0}.footer{display:flex;justify-content:space-between;padding:18px 32px;border-top:1px solid var(--line);color:var(--muted);font-size:12px}@media(max-width:1050px){.kpis{grid-template-columns:repeat(3,1fr)}.grid{grid-template-columns:1fr 1fr}.span2{grid-column:span 2}}@media(max-width:680px){.hero{display:block;padding:27px 19px}.status{margin-top:18px}main{padding:17px}.kpis,.grid{grid-template-columns:1fr}.span2{grid-column:auto}.toolbar{padding:11px 17px;overflow:auto}.matrix{font-size:8px;grid-template-columns:75px repeat(5,1fr)}.footer{display:block}}
</style></head><body><div class="shell"><header class="hero"><div><div class="eyebrow">RESPONSIBLE AI · CUSTOMER OPERATIONS</div><h1>SUPPORT-TICKET<br>INTELLIGENCE</h1><p>Interpretable routing, human oversight, fairness monitoring, and operational impact</p></div><div class="status"><small>DEPLOYMENT DECISION</small><b id="status">—</b><span>Governed automation</span></div></header><nav class="toolbar"><span>Analyze:</span><button class="filter active" data-view="language">Language equity</button><button class="filter" data-view="channel">Channel</button><button class="filter" data-view="queue">Support queue</button></nav><main><section class="kpis"><div class="kpi"><label>Tickets analyzed</label><strong id="tickets">—</strong><small>60-day evaluation</small></div><div class="kpi"><label>Automated accuracy</label><strong id="autoAccuracy">—</strong><small>Auto-routed tickets only</small></div><div class="kpi"><label>Automation coverage</label><strong id="coverage">—</strong><small>Remaining tickets reviewed</small></div><div class="kpi"><label>Average latency</label><strong id="latency">—</strong><small>Milliseconds</small></div><div class="kpi"><label>Equity gap</label><strong id="gap">—</strong><small>Language accuracy range</small></div></section><section class="grid">
<article class="panel"><h2>▣ Executive Summary</h2><div class="body"><div class="decision"><b id="decision">—</b><span>Deploy only with active monitoring and human escalation.</span></div><div class="check"><span>High-risk cases auto-routed</span><b class="pass" id="risk">0</b></div><div class="check"><span>Accuracy quality gate</span><b class="pass" id="quality">PASS</b></div><div class="check"><span>Language equity gate</span><b class="pass" id="equity">PASS</b></div><div class="insight"><b>Human-in-the-loop design</b><br>Uncertain, ambiguous, unsupported, and high-risk cases are deliberately withheld from automation.</div></div></article>
<article class="panel span2"><h2>▣ 60-Day Model Monitoring</h2><div class="body"><div class="legend"><span style="color:var(--green)">● Accuracy</span><span style="color:var(--blue)">● Automation</span></div><div class="line-wrap"><svg id="trend" viewBox="0 0 760 235" aria-label="Daily accuracy and automation"></svg></div></div></article>
<article class="panel green"><h2>▣ Fairness & Performance</h2><div class="body"><div class="chart-title" id="segmentTitle">Accuracy and automation by language</div><div class="legend"><span style="color:var(--green)">● Accuracy</span><span style="color:var(--blue)">● Automation</span></div><div class="bars" id="bars"></div></div></article>
<article class="panel"><h2>▣ Human Review Queue</h2><div class="body" id="reviews"></div></article>
<article class="panel orange"><h2>▣ Governance Recommendations</h2><div class="body"><p><b>1 · Keep high-risk hard stops</b><br>Never auto-route fraud, safety, legal, or discrimination signals.</p><p><b>2 · Improve multilingual coverage</b><br>Add reviewed Spanish and Hindi examples before raising coverage.</p><p><b>3 · Monitor selective accuracy</b><br>Track both accuracy and automation rate; either can hide harm.</p><p><b>4 · Audit monthly</b><br>Review drift, overrides, escalation outcomes, cost, and latency.</p></div></article>
<article class="panel red span2"><h2>▣ Routing Confusion Matrix</h2><div class="body"><div class="chart-title">Rows = actual queue · columns = predicted queue</div><div class="matrix" id="matrix"></div></div></article>
<article class="panel"><h2>▣ Operational Impact</h2><div class="body"><div class="check"><span>Total estimated cost</span><b id="cost">—</b></div><div class="check"><span>Average confidence</span><b id="confidence">—</b></div><div class="check"><span>Accuracy gap</span><b id="accuracyGap">—</b></div><div class="check"><span>Automation gap</span><b id="automationGap">—</b></div><p style="color:var(--muted);font-size:12px">Cost includes simulated model inference and human-review handling.</p></div></article>
</section></main><footer class="footer"><span>Built by Divya Dhole · Python · SQL · SQLite · Vanilla JavaScript</span><span>Interpretable model · Human oversight · Responsible deployment</span></footer></div><script>const D=__DATA__,E=D.evaluation,$=s=>document.querySelector(s),fmt=n=>n.toLocaleString(),pct=n=>Number(n).toFixed(1)+'%';$('#tickets').textContent=fmt(E.tickets);$('#autoAccuracy').textContent=pct(E.automated_accuracy_pct);$('#coverage').textContent=pct(E.automation_pct);$('#latency').textContent=Math.round(E.avg_latency_ms)+' ms';$('#gap').textContent=E.accuracy_gap_pp.toFixed(1)+' pp';$('#status').textContent=E.deployment_status.toUpperCase();$('#decision').textContent=E.deployment_status;$('#risk').textContent=E.high_risk_escaped;$('#quality').textContent=E.automated_accuracy_pct>=90?'PASS':'FAIL';$('#equity').textContent=E.accuracy_gap_pp<=12?'PASS':'REMEDIATE';$('#cost').textContent='$'+E.total_cost_usd.toFixed(2);$('#confidence').textContent=E.avg_confidence.toFixed(3);$('#accuracyGap').textContent=E.accuracy_gap_pp.toFixed(2)+' pp';$('#automationGap').textContent=E.automation_gap_pp.toFixed(2)+' pp';
const cap=s=>s.split('_').map(x=>x[0].toUpperCase()+x.slice(1)).join(' ');function render(view){let groups;if(view==='language')groups=D.languages.map(x=>({name:x.language,a:x.accuracy_pct,c:x.automation_pct}));else if(view==='channel')groups=[...new Set(D.subgroups.map(x=>x.channel))].map(ch=>{let r=D.subgroups.filter(x=>x.channel===ch),n=r.reduce((s,x)=>s+x.tickets,0);return{name:ch,a:r.reduce((s,x)=>s+x.accuracy_pct*x.tickets,0)/n,c:r.reduce((s,x)=>s+x.automation_pct*x.tickets,0)/n}});else groups=D.queues.map(x=>({name:x.true_queue,a:x.recall_pct,c:x.automation_pct}));$('#segmentTitle').textContent=(view==='queue'?'Recall and automation by support queue':'Accuracy and automation by '+view);$('#bars').innerHTML=groups.map(g=>`<div style="margin-bottom:16px"><b style="font-size:12px">${cap(g.name)}</b><div class="bar-row"><span>Accuracy</span><div class="track"><div class="bar" style="width:${g.a}%;background:var(--green)"></div></div><b>${pct(g.a)}</b></div><div class="bar-row"><span>Automation</span><div class="track"><div class="bar" style="width:${g.c}%;background:var(--blue)"></div></div><b>${pct(g.c)}</b></div></div>`).join('')}document.querySelectorAll('.filter').forEach(b=>b.onclick=()=>{document.querySelectorAll('.filter').forEach(x=>x.classList.remove('active'));b.classList.add('active');render(b.dataset.view)});render('language');
$('#reviews').innerHTML=D.reviews.map(x=>`<div class="review"><b><span>${cap(x.review_reason)}</span><span>${fmt(x.tickets)}</span></b><span class="tag">${pct(x.review_share_pct)} of review load</span></div>`).join('');let qs=[...new Set(D.confusion.map(x=>x.true_queue))];let max=Math.max(...D.confusion.map(x=>x.tickets));let html='<div class="cell head">Actual ↓ / Predicted →</div>'+qs.map(cap).map(x=>`<div class="cell head">${x}</div>`).join('');qs.forEach(a=>{html+=`<div class="cell head">${cap(a)}</div>`;qs.forEach(p=>{let x=D.confusion.find(v=>v.true_queue===a&&v.predicted_queue===p),n=x?x.tickets:0,alpha=.08+.82*n/max;html+=`<div class="cell" style="background:rgba(23,105,170,${alpha}) ;color:${alpha>.5?'white':'var(--ink)'}">${n}</div>`})});$('#matrix').innerHTML=html;
function trend(){let svg=$('#trend'),W=760,H=235,p=35,rows=D.daily;let xy=(v,i)=>[p+i*(W-p*2)/(rows.length-1),H-p-(v-40)*(H-p*2)/60],out='';for(let y=40;y<=100;y+=15){let py=xy(y,0)[1];out+=`<line class="gridline" x1="${p}" y1="${py}" x2="${W-p}" y2="${py}"/><text x="2" y="${py+4}" fill="#6a7b8e" font-size="10">${y}%</text>`}[["accuracy_pct","accuracy"],["automation_pct","automation"]].forEach(([k,cl])=>{out+=`<polyline class="${cl}" points="${rows.map((x,i)=>xy(x[k],i).join(',')).join(' ')}"/>`});out+=`<line class="axis" x1="${p}" y1="${H-p}" x2="${W-p}" y2="${H-p}"/>`;svg.innerHTML=out}trend();</script></body></html>'''

